#nullable enable // autogenerated

using MVZ2Logic;
using MVZ2Logic.Entities;
using MVZ2Logic.Definitions;
using MVZ2Logic.Definitions;
using MVZ2Logic.Options;
using MVZ2Logic.Saves;

namespace MVZ2.GameContent.Options
{
    [AutoOptionWidgetDefinition(LogicOptionWidgetNames.hpBarsEnabled)]
    public class HPBarsEnabledOptionToggle : OptionToggleDefinition
    {
        public HPBarsEnabledOptionToggle(string nsp, string name) : base(nsp, name)
        {
        }
        public override bool ShouldEnable(IOptionContext context)
        {
            return Global.Saves.IsHPBarUnlocked() || Global.Debugs.CanUseDebugFeatures();
        }
        public override bool GetValue(IOptionContext context)
        {
            return Global.Options.GetOptionBool(LogicOptionItemID.hpBarEnabled);
        }

        public override void OnValueChanged(IOptionContext context, bool value)
        {
            Global.Options.SetOptionBool(LogicOptionItemID.hpBarEnabled, value);
            Global.Options.SaveOptions();
        }
    }
}
